#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it)); c = int(next(it))
        if a > 50:
            out.append('A')
        elif b > 50:
            out.append('B')
        elif c > 50:
            out.append('C')
        else:
            out.append('NOTA')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

